  ('heelevel3-d592fc58-moex-00265', 'heelevel3-d592fc58', 'heelevel3-d592fc58-moex-110-3082b5f1', 'sub-heelevel3-d592fc58-06', NULL, 'single_choice', '下列何者非屬對外發生法律效果之規定？', '["公民與政治權利國際公約及經濟社會文化權利國際公約施行法", "大學法施行細則", "地方稅法通則", "中央政府年度總預算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:54+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "333", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "商業行政"}'::jsonb, NULL),
